import React, { useState, useEffect, useCallback } from 'react';
import { Card, Form, Button, Table, Badge, Modal, Pagination } from 'react-bootstrap';
import { Search, Eye, Download, History, Upload } from 'lucide-react';
import { toast } from 'react-toastify';
import { searchDocuments, downloadDocument } from '../api';
import DocumentPreview from './DocumentPreview';
import VersionHistory from './VersionHistory';
import UpdateDocumentModal from './UpdateDocumentModal';
import './DocumentRetrieval.css';

const DocumentRetrieval = () => {
  const [searchCriteria, setSearchCriteria] = useState({
    employeeId: '',
    employeeName: '',
    store: '',
    documentType: '',
    issueDate: '',
    expiryDate: ''
  });
  const [filteredDocuments, setFilteredDocuments] = useState([]);
  const [sortConfig, setSortConfig] = useState({ key: null, direction: 'asc' });
  const [previewDocument, setPreviewDocument] = useState(null);
  const [showPreview, setShowPreview] = useState(false);
  const [showVersionHistory, setShowVersionHistory] = useState(false);
  const [selectedDocumentForVersion, setSelectedDocumentForVersion] = useState(null);
  const [showUpdateModal, setShowUpdateModal] = useState(false);
  const [selectedDocumentForUpdate, setSelectedDocumentForUpdate] = useState(null);
  
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);
  const [pageSizeInput, setPageSizeInput] = useState('10');

  const loadDocuments = useCallback(async () => {
    try {
      const response = await searchDocuments({});
      if (response.data && response.data.data) {
        const docs = response.data.data.map(doc => ({
          ...doc,
          status: getStatusColor(doc.expiryDate)
        }));
        setFilteredDocuments(docs);
        setCurrentPage(1);
      }
    } catch (error) {
      console.error('Error loading documents:', error);
      setFilteredDocuments([]);
    }
  }, []);

  useEffect(() => {
    loadDocuments();
  }, [loadDocuments]);

  const documentTypes = [
    'ID Proof',
    'Driving License',
    'Medical Certificate',
    'Training Certificate',
    'Employment Contract',
    'Educational Certificate',
    'Address Proof',
    'Police Verification'
  ];

  const stores = Array.from({ length: 20 }, (_, i) => `Store ${i + 1}`);

  const getStatusBadge = (status) => {
    const badges = {
      valid: { variant: 'success', text: 'Valid' },
      expiring: { variant: 'warning', text: 'Expiring Soon' },
      expired: { variant: 'danger', text: 'Expired' }
    };
    return badges[status] || badges.valid;
  };

  const getStatusColor = (expiryDate) => {
    if (!expiryDate) return 'valid';
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const expiry = new Date(expiryDate);
    expiry.setHours(0, 0, 0, 0);
    const daysUntilExpiry = Math.floor((expiry - today) / (1000 * 60 * 60 * 24));
    
    if (daysUntilExpiry <= 0) return 'expired';
    if (daysUntilExpiry <= 30) return 'expiring';
    return 'valid';
  };

  const handleSearch = async () => {
    try {
      const response = await searchDocuments(searchCriteria);
      if (response.data && response.data.data) {
        const results = response.data.data.map(doc => ({
          ...doc,
          status: getStatusColor(doc.expiryDate)
        }));
        setFilteredDocuments(results);
        setCurrentPage(1);
        toast.info(`Found ${results.length} document(s)`);
        position: 'top-right'
        
      }
    } catch (error) {
      toast.error('Error searching documents');
      position: 'top-right',
      
      console.error(error);
    }
  };

  const handleReset = () => {
    setSearchCriteria({
      employeeId: '',
      employeeName: '',
      store: '',
      documentType: '',
      issueDate: '',
      expiryDate: ''
    });
    setCurrentPage(1);
    loadDocuments();
  };

  const handleSort = (key) => {
    let direction = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });

    const sorted = [...filteredDocuments].sort((a, b) => {
      if (a[key] < b[key]) return direction === 'asc' ? -1 : 1;
      if (a[key] > b[key]) return direction === 'asc' ? 1 : -1;
      return 0;
    });

    setFilteredDocuments(sorted);
  };

  const handleView = (doc) => {
    setPreviewDocument(doc);
    setShowPreview(true);
  };

  const handleDownload = async (doc) => {
    try {
      const docId = doc.id.replace('DOC', '');
      const response = await downloadDocument(docId);
      const blob = response.data instanceof Blob ? response.data : new Blob([response.data], { type: response.headers?.['content-type'] });
      const url = URL.createObjectURL(blob);
      const link = window.document.createElement('a');
      link.href = url;
      link.download = doc.fileName || 'document';
      window.document.body.appendChild(link);
      link.click();
      window.document.body.removeChild(link);
      URL.revokeObjectURL(url);
      toast.success('Document downloaded successfully');
    } catch (error) {
      toast.error('Error downloading document');
    }
  };

  const totalPages = Math.ceil(filteredDocuments.length / pageSize);
  const startIndex = (currentPage - 1) * pageSize;
  const endIndex = startIndex + pageSize;
  const currentDocuments = filteredDocuments.slice(startIndex, endIndex);

  const handlePageChange = (page) => {
    setCurrentPage(page);
  };

  const handlePageSizeChange = (e) => {
    const value = e.target.value;
    setPageSizeInput(value);
    
    if (value === '') {
      setPageSize(10);
      setCurrentPage(1);
      return;
    }
    
    const numValue = parseInt(value, 10);
    if (!isNaN(numValue) && numValue >= 1 && numValue <= 100) {
      setPageSize(numValue);
      setCurrentPage(1);
    }
  };

  const getPaginationItems = () => {
    const items = [];
    const maxVisible = 5;
    
    if (totalPages <= maxVisible) {
      for (let i = 1; i <= totalPages; i++) {
        items.push(i);
      }
    } else {
      if (currentPage <= 3) {
        for (let i = 1; i <= 4; i++) items.push(i);
        items.push('...');
        items.push(totalPages);
      } else if (currentPage >= totalPages - 2) {
        items.push(1);
        items.push('...');
        for (let i = totalPages - 3; i <= totalPages; i++) items.push(i);
      } else {
        items.push(1);
        items.push('...');
        items.push(currentPage - 1);
        items.push(currentPage);
        items.push(currentPage + 1);
        items.push('...');
        items.push(totalPages);
      }
    }
    
    return items;
  };

  return (
    <div className="document-retrieval">
      <Card className="retrieval-card">
        <Card.Header className="card-header-custom">
          <h3 className="mb-0">
            <Search className="me-2" size={24} />
            Document Retrieval & Search
          </h3>
        </Card.Header>
        <Card.Body>
          <Card className="search-card mb-4">
            <Card.Body>
              <div className="row g-3 mb-3">
                <div className="col-md-4">
                  <Form.Label>Employee ID</Form.Label>
                  <Form.Control
                    type="text"
                    placeholder="Enter Employee ID"
                    value={searchCriteria.employeeId}
                    onChange={(e) => setSearchCriteria({ ...searchCriteria, employeeId: e.target.value })}
                  />
                </div>
                <div className="col-md-4">
                  <Form.Label>Employee Name</Form.Label>
                  <Form.Control
                    type="text"
                    placeholder="Enter Employee Name"
                    value={searchCriteria.employeeName}
                    onChange={(e) => setSearchCriteria({ ...searchCriteria, employeeName: e.target.value })}
                  />
                </div>
                <div className="col-md-4">
                  <Form.Label>Store</Form.Label>
                  <Form.Select
                    value={searchCriteria.store}
                    onChange={(e) => setSearchCriteria({ ...searchCriteria, store: e.target.value })}
                  >
                    <option value="">All Stores</option>
                    {stores.map(store => (
                      <option key={store} value={store}>{store}</option>
                    ))}
                  </Form.Select>
                </div>
              </div>

              <div className="row g-3 mb-3">
                <div className="col-md-4">
                  <Form.Label>Document Type</Form.Label>
                  <Form.Select
                    value={searchCriteria.documentType}
                    onChange={(e) => setSearchCriteria({ ...searchCriteria, documentType: e.target.value })}
                  >
                    <option value="">All Types</option>
                    {documentTypes.map(type => (
                      <option key={type} value={type}>{type}</option>
                    ))}
                  </Form.Select>
                </div>
                <div className="col-md-4">
                  <Form.Label>Issue Date</Form.Label>
                  <Form.Control
                    type="date"
                    value={searchCriteria.issueDate}
                    onChange={(e) => setSearchCriteria({ ...searchCriteria, issueDate: e.target.value })}
                  />
                </div>
                <div className="col-md-4">
                  <Form.Label>Expiry Date</Form.Label>
                  <Form.Control
                    type="date"
                    value={searchCriteria.expiryDate}
                    onChange={(e) => setSearchCriteria({ ...searchCriteria, expiryDate: e.target.value })}
                  />
                </div>
              </div>

              <div className="d-flex justify-content-center gap-2">
                <Button variant="primary" onClick={handleSearch} className="px-4">
                  <Search className="me-2" size={18} />
                  Search
                </Button>
                <Button variant="outline-secondary" onClick={handleReset} className="px-4">
                  Reset
                </Button>
              </div>
            </Card.Body>
          </Card>

          <div className="d-flex align-items-center gap-2 mb-3">
            <span className="text-muted">Show</span>
            <Form.Control
              type="number"
              size="sm"
              min="1"
              max="100"
              placeholder="10"
              style={{ width: '80px' }}
              value={pageSizeInput}
              onChange={handlePageSizeChange}
            />
            <span className="text-muted">entries</span>
          </div>

          <div className="table-responsive">
            <Table hover className="results-table">
              <thead>
                <tr>
                  <th onClick={() => handleSort('id')} className="sortable">
                    <strong>Document ID</strong> {sortConfig.key === 'id' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                  <th onClick={() => handleSort('employeeName')} className="sortable">
                    <strong>Employee Name</strong> {sortConfig.key === 'employeeName' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                  <th onClick={() => handleSort('store')} className="sortable">
                    <strong>Store</strong> {sortConfig.key === 'store' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                  <th onClick={() => handleSort('documentType')} className="sortable">
                    <strong>Document Type</strong> {sortConfig.key === 'documentType' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                  <th onClick={() => handleSort('expiryDate')} className="sortable">
                    <strong>Expiry Date</strong> {sortConfig.key === 'expiryDate' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                  <th><strong>Status</strong></th>
                  <th><strong>Actions</strong></th>
                </tr>
              </thead>
              <tbody>
                {currentDocuments.length === 0 ? (
                  <tr>
                    <td colSpan="7" className="text-center py-5 text-muted">
                      No documents found. Try adjusting your search criteria.
                    </td>
                  </tr>
                ) : (
                  currentDocuments.map((doc) => {
                    const status = getStatusBadge(doc.status);
                    return (
                      <tr key={doc.id}>
                        <td>{doc.id}</td>
                        <td>
                          <div>
                            {doc.employeeName}
                            <br />
                            <small className="text-muted">{doc.employeeId}</small>
                          </div>
                        </td>
                        <td>{doc.store}</td>
                        <td>{doc.documentType}</td>
                        <td>{doc.expiryDate || 'N/A'}</td>
                        <td>
                          <Badge bg={status.variant}>{status.text}</Badge>
                        </td>
                        <td>
                          <div className="action-buttons">
                            <Button
                              variant="link"
                              size="sm"
                              onClick={() => handleView(doc)}
                              className="action-btn"
                              title="View"
                            >
                              <Eye size={18} />
                            </Button>
                            <Button
                              variant="link"
                              size="sm"
                              onClick={() => handleDownload(doc)}
                              className="action-btn"
                              title="Download"
                            >
                              <Download size={18} />
                            </Button>
                            <Button
                              variant="link"
                              size="sm"
                              onClick={() => {
                                setSelectedDocumentForVersion(doc.id);
                                setShowVersionHistory(true);
                              }}
                              className="action-btn"
                              title="Version History"
                            >
                              <History size={18} />
                            </Button>
                            <Button
                              variant="link"
                              size="sm"
                              onClick={() => {
                                let docId = doc.id;
                                if (typeof docId === 'string' && docId.startsWith('DOC')) {
                                  docId = parseInt(docId.replace('DOC', ''), 10);
                                }
                                setSelectedDocumentForUpdate(docId);
                                setShowUpdateModal(true);
                              }}
                              className="action-btn"
                              title="Update Document"
                            >
                              <Upload size={18} />
                            </Button>
                          </div>
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </Table>
          </div>

          {filteredDocuments.length > 0 && (
            <div className="d-flex justify-content-between align-items-center mt-3">
              <div className="text-muted">
                Showing {startIndex + 1} to {Math.min(endIndex, filteredDocuments.length)} of {filteredDocuments.length} entries
              </div>
              <Pagination className="mb-0">
                <Pagination.First 
                  onClick={() => handlePageChange(1)} 
                  disabled={currentPage === 1}
                />
                <Pagination.Prev 
                  onClick={() => handlePageChange(currentPage - 1)} 
                  disabled={currentPage === 1}
                />
                
                {getPaginationItems().map((item, index) => (
                  item === '...' ? (
                    <Pagination.Ellipsis key={`ellipsis-${index}`} disabled />
                  ) : (
                    <Pagination.Item
                      key={item}
                      active={item === currentPage}
                      onClick={() => handlePageChange(item)}
                    >
                      {item}
                    </Pagination.Item>
                  )
                ))}
                
                <Pagination.Next 
                  onClick={() => handlePageChange(currentPage + 1)} 
                  disabled={currentPage === totalPages}
                />
                <Pagination.Last 
                  onClick={() => handlePageChange(totalPages)} 
                  disabled={currentPage === totalPages}
                />
              </Pagination>
            </div>
          )}
        </Card.Body>
      </Card>
      
      <DocumentPreview
        show={showPreview}
        onHide={() => {
          setShowPreview(false);
          setPreviewDocument(null);
        }}
        document={previewDocument}
      />

      <Modal show={showVersionHistory} onHide={() => setShowVersionHistory(false)} size="lg" centered>
        <Modal.Header closeButton>
          <Modal.Title>
            <History className="me-2" size={20} />
            Version History
          </Modal.Title>
        </Modal.Header>
        <Modal.Body>
          {selectedDocumentForVersion && (
            <VersionHistory documentId={selectedDocumentForVersion} />
          )}
        </Modal.Body>
      </Modal>

      <UpdateDocumentModal
        show={showUpdateModal}
        onHide={() => setShowUpdateModal(false)}
        documentId={selectedDocumentForUpdate}
        onUpdated={() => {
          loadDocuments();
        }}
      />
    </div>
  );
};

export default DocumentRetrieval;
